System.register(["./mediaSources-legacy-BSnuTFlr.js"],function(e,t){var n,a;return{setters:[function(e){n=e.t}],execute:function(){e("n",{unit5:n("a2-video/unit5.mp4",(a={unit5:"https://dlink.host/1drv/aHR0cHM6Ly8xZHJ2Lm1zL3YvYy9mZTE5MTBhZWYzZGExMTM1L0lRRHRYRHhzel9nVlQ0WEp1VTFTRld3akFYNTFWRloxajNuMHBwTXluTmtkRGdjP2U9OVdCenhV.mp4",unit6:"https://dlink.host/1drv/aHR0cHM6Ly8xZHJ2Lm1zL3YvYy9mZTE5MTBhZWYzZGExMTM1L0lRQnl3VW1JTnB0alJwelV3cERYYkhHYUFlWWk2Zjdmc2R6SGwzemdibHBueS1zP2U9QTdkaUZC.mp4",unit7:"https://dlink.host/1drv/aHR0cHM6Ly8xZHJ2Lm1zL3YvYy9mZTE5MTBhZWYzZGExMTM1L0lRRHBMU3EyU1RsLVNwYXdiVVJ5NUwwUkFYQ3lUWllsYVB6VVZHeHBUMERqRXdJP2U9b1VrRmtS.mp4",unit8:"https://dlink.host/1drv/aHR0cHM6Ly8xZHJ2Lm1zL3YvYy9mZTE5MTBhZWYzZGExMTM1L0lRRFF4cmlBZmNNWlNaSjVSazlKY1B2c0FXdDBXU2lQUFpReFlQRWdaZHAwY3F3P2U9c3BBWnR2.mp4"}).unit5),unit6:n("a2-video/unit6.mp4",a.unit6),unit7:n("a2-video/unit7.mp4",a.unit7),unit8:n("a2-video/unit8.mp4",a.unit8)}),e("t",{unit5:[{start:2.366,end:5.333,en:"Psst. Psst! Hey, Buzz!",zh:"嘘。嘘！嘿，巴斯！"},{start:11.5,end:12.833,en:"Hey.",zh:"嘿。"},{start:12.833,end:18.033,en:"Get over here and see if you can get this toolbox off me.",zh:"过来看看你能不能帮我把这个工具箱弄走。"},{start:18.033,end:21.666,en:"Oh, come on, Buzz, I...",zh:"哦，拜托，巴斯，我……"},{start:21.666,end:26.066,en:"Buzz, I can't do this without you. I need your help.",zh:"巴斯，没有你我做不到。我需要你的帮助。"},{start:26.066,end:30.533,en:"I can't help. I can't help anyone.",zh:"我帮不上忙。我帮不了任何人。"},{start:30.533,end:33.866,en:"Why, sure you can, Buzz. You can get me outta here.",zh:"怎么会，你当然可以，巴斯。你可以把我弄出去。"},{start:33.866,end:36.866,en:"Then I'll get that rocket off you, and we'll make a break for Andy's house.",zh:"然后我帮你把那个火箭弄下来，我们一起逃回安迪的家。"},{start:36.866,end:40.266,en:"Andy's house, Sid's house. What's the difference?",zh:"安迪的家，席德的家。有什么区别？"},{start:40.266,end:44.6,en:"Oh, Buzz. You've had a big fall. You must not be thinking clearly.",zh:"哦，巴斯。你摔得太重了。你一定是不清醒了。"},{start:44.6,end:47.966,en:"No, Woody. For the first time I am thinking clearly.",zh:"不，胡迪。这是我第一次想得这么清楚。"},{start:47.966,end:51.666,en:"You were right all along. I'm not a Space Ranger.",zh:"你一直都是对的。我不是太空骑警。"},{start:51.666,end:55.566,en:"I'm just a toy, a stupid, little, insignificant toy.",zh:"我只是个玩具，一个愚蠢、渺小、微不足道的玩具。"},{start:55.566,end:57.1,en:"Whoa, hey, wait a minute.",zh:"哇，嘿，等一下。"},{start:57.1,end:60.6,en:"Bein' a toy is a lot better than bein' a, a Space Ranger.",zh:"做一个玩具比做一个……太空骑警好多了。"}],unit6:[{start:.333,end:3.266,en:"I spent the summer devising a whole new Quidditch program.",zh:"我花了一整个夏天设计了全新的魁地奇训练计划。"},{start:3.266,end:7.066,en:"We're gonna train earlier, harder and longer.",zh:"我们要练得更早、更狠、时间更长。"},{start:7.066,end:10.433,en:"What-? I don't believe it.",zh:"什么——？我简直不敢相信。"},{start:13.133,end:16.033,en:"- Where you think you're going, Flint? - Quidditch practice.",zh:"- 你以为你要去哪里，弗林特？ - 魁地奇训练。"},{start:16.033,end:18,en:"I booked the pitch for Gryffindor today.",zh:"我今天为格兰芬多预定了球场。"},{start:18,end:20.4,en:"Easy, Wood. I've got a note.",zh:"别激动，伍德。我有张条子。"},{start:21.833,end:24.033,en:"Uh-oh. I smell trouble.",zh:"呃哦。我闻到了麻烦的味道。"},{start:24.666,end:28.333,en:'"I, Professor Severus Snape, do hereby give the Slytherin team...',zh:"“我，西弗勒斯·斯内普教授，特此批准斯莱特林球队……"},{start:28.333,end:31.833,en:'...permission to practice today, owing to the need to train their new Seeker. "',zh:"……今天进行训练，因为他们需要训练新的找球手。”"},{start:32,end:34.666,en:"You've got a new Seeker. Who?",zh:"你们有了新的找球手。是谁？"},{start:38.666,end:41.233,en:"- Malfoy? - That's right.",zh:"- 马尔福？ - 没错。"},{start:41.433,end:44.2,en:"And that's not all that's new this year.",zh:"而且这还不是今年唯一的新鲜事。"},{start:45.066,end:48.5,en:"Those are Nimbus 2001 s. How did you get those?",zh:"那是光轮2001。你们怎么弄到的？"},{start:48.7,end:50.733,en:"A gift from Draco's father.",zh:"德拉科父亲送的礼物。"},{start:50.9,end:54.666,en:"You see, Weasley, unlike some, my father can afford the best.",zh:"你看，韦斯莱，不像某些人，我父亲买得起最好的。"},{start:54.866,end:57.866,en:"At least no one on the Gryffindor team had to buy their way in.",zh:"至少格兰芬多队里没有人是靠花钱进来的。"},{start:58.033,end:60.9,en:"They got in on pure talent.",zh:"他们全凭真正的天赋入选。"}],unit7:[{start:4.5,end:5.3,en:"Tadashi.",zh:"塔达希（泰迪）。"},{start:7.2,end:7.866,en:"What?",zh:"什么？"},{start:9.433,end:10.366,en:"Tadashi.",zh:"塔达希（泰迪）。"},{start:15.5,end:17.2,en:"Tadashi's gone.",zh:"塔达希不在了。"},{start:17.2,end:19.6,en:"When will he return?",zh:"他什么时候回来？"},{start:19.6,end:21.266,en:"He's dead, Baymax.",zh:"他死了，大白。"},{start:26.2,end:28.933,en:"Tadashi was in excellent health.",zh:"塔达希的身体状况非常健康。"},{start:28.933,end:31,en:"With a proper diet and exercise,",zh:"加上适当的饮食和锻炼，"},{start:31,end:33.433,en:"he should have lived a long life.",zh:"他本应该长寿的。"},{start:33.433,end:36.066,en:"Yeah, he should have.",zh:"是啊，他本该如此。"},{start:37.4,end:38.966,en:"But there was a fire...",zh:"但是发生了一场火灾……"},{start:40.966,end:42.233,en:"Now, he's gone.",zh:"现在，他不在了。"},{start:43.8,end:46.233,en:"- Tadashi is here. - No.",zh:"- 塔达希在这里。 - 不。"},{start:46.233,end:48.8,en:"People keep saying he's not really gone.",zh:"人们总是说他并没有真的离开。"},{start:48.8,end:50.833,en:"As long as we remember him.",zh:"只要我们还记得他。"},{start:53.966,end:55.866,en:"It still hurts.",zh:"可是依然很痛。"},{start:55.866,end:58.433,en:"I see no evidence of physical injury.",zh:"我没有发现任何身体受伤的迹象。"}],unit8:[{start:.166,end:1.533,en:"We're ready!",zh:"我们准备好了！"},{start:5,end:7.8,en:"If only Martha were here to see this.",zh:"如果玛莎能在这里看到这一切就好了。"},{start:7.8,end:10.366,en:"She's always here, Wanda.",zh:"她一直都在，旺达。"},{start:10.366,end:11.466,en:"Okay, friends,",zh:"好了，朋友们，"},{start:11.466,end:15.066,en:"I am so glad you are here to celebrate.",zh:"我很高兴你们能来这里庆祝。"},{start:15.066,end:18.2,en:"Another birthday for my sweet little Mavis,",zh:"为我甜美的小梅菲丝庆祝又一个生日，"},{start:18.2,end:23,en:"and another successful year of refuge from them!",zh:"并庆祝我们又成功躲避了他们一年！"},{start:24.966,end:28.566,en:"These are recent human images our surveillance has uncovered.",zh:"这是我们的监控设备最近拍到的人类影像。"},{start:28.566,end:32.333,en:"They are getting fatter so as to overpower us.",zh:"他们变得越来越胖，为的是在力量上压倒我们。"},{start:32.333,end:34,en:"And they are wearing less clothing,",zh:"而且他们穿得越来越少，"},{start:34,end:36.366,en:"allowing more movement to strangle us",zh:"以便更灵活地勒死我们，"},{start:36.366,end:39.466,en:"or cut open our heads and put candy in them.",zh:"或者切开我们的脑袋，把糖果塞进去。"},{start:39.466,end:42.2,en:"But they will never find us here.",zh:"但他们永远不会在这里找到我们。"},{start:42.2,end:45.133,en:"Evil villain, you will never win!",zh:"邪恶的恶棍，你永远不会赢！"},{start:45.133,end:47.566,en:"Okay-doke. The fun starts in 30 minutes.",zh:"好吧。狂欢在30分钟后开始。"},{start:47.566,end:49.966,en:"Right now, I have to see my little girl.",zh:"现在，我得去看看我的小女儿。"},{start:49.966,end:51.766,en:"She's not so little anymore!",zh:"她已经不小了！"},{start:51.766,end:53.3,en:"Yes, she is!",zh:"不，她还小！"},{start:56.266,end:57.766,en:"What's going on out there?",zh:"外面发生了什么事？"},{start:57.766,end:59.266,en:"Are we at the hotel?",zh:"我们到酒店了吗？"},{start:59.266,end:62.533,en:"Frank, did you book us for a tandem message?",zh:"弗兰克，你给我们订了双人按摩吗？"},{start:62.533,end:64.7,en:"Did you get us a table at Hunchback's?",zh:"你在钟楼怪人餐厅订到位子了吗？"},{start:64.7,end:66.266,en:"Did you do anything?",zh:"你到底做了什么没有？"},{start:67.233,end:68.566,en:"You're welcome.",zh:"不客气。"},{start:68.566,end:69.8,en:"What's going on?",zh:"怎么回事？"}]})}}});